import { request } from "@umijs/max";
export async function login(params) {
  return request("/api/auth/login", {
    method: "POST",
    data: params
  });
}
export async function getCurrentUser() {
  return request("/api/auth/currentUser", {
    method: "GET"
  });
}
export async function getDashboardStats() {
  return request("/api/dashboard/stats", {
    method: "GET"
  });
}
export async function getMuseumList(params) {
  return request("/api/museum/list", {
    method: "GET",
    params
  });
}
export async function createMuseum(data) {
  return request("/api/museum/create", {
    method: "POST",
    data
  });
}
export async function updateMuseum(id, data) {
  return request(`/api/museum/update/${id}`, {
    method: "PUT",
    data
  });
}
export async function deleteMuseum(id) {
  return request(`/api/museum/delete/${id}`, {
    method: "DELETE"
  });
}
export async function getUGCList(params) {
  return request("/api/ugc/list", {
    method: "GET",
    params
  });
}
export async function approveUGC(id) {
  return request(`/api/ugc/approve/${id}`, {
    method: "POST"
  });
}
export async function rejectUGC(id) {
  return request(`/api/ugc/reject/${id}`, {
    method: "POST"
  });
}
export async function getUserList(params) {
  return request("/api/user/list", {
    method: "GET",
    params
  });
}
export async function createUser(data) {
  return request("/api/user/create", {
    method: "POST",
    data
  });
}
export async function updateUser(id, data) {
  return request(`/api/user/update/${id}`, {
    method: "PUT",
    data
  });
}
export async function deleteUser(id) {
  return request(`/api/user/delete/${id}`, {
    method: "DELETE"
  });
}
